"use strict";(self.webpackChunkwp_wallet_system_doc=self.webpackChunkwp_wallet_system_doc||[]).push([[882],{8427(e,a,t){t.r(a),t.d(a,{comp:()=>l,data:()=>i});var s=t(641);const n={class:"hint-container tip"},o={},l=(0,t(6262).A)(o,[["render",function(e,a){const t=(0,s.g2)("RouteLink");return(0,s.uX)(),(0,s.CE)("div",null,[a[7]||(a[7]=(0,s.Lk)("h1",{id:"paypal-payout",tabindex:"-1"},[(0,s.Lk)("a",{class:"header-anchor",href:"#paypal-payout"},[(0,s.Lk)("span",null,"PayPal Payout")])],-1)),a[8]||(a[8]=(0,s.Lk)("p",null,"Pay out approved wallet withdrawals to a customer's PayPal email automatically.",-1)),(0,s.Lk)("div",n,[a[3]||(a[3]=(0,s.Lk)("p",{class:"hint-container-title"},"Setting up?",-1)),(0,s.Lk)("p",null,[a[1]||(a[1]=(0,s.eW)("Skip to ",-1)),(0,s.Lk)("strong",null,[(0,s.bF)(t,{to:"/admin-settings/payout.html"},{default:(0,s.k6)(()=>[...a[0]||(a[0]=[(0,s.eW)("Payout Settings → PayPal",-1)])]),_:1})]),a[2]||(a[2]=(0,s.eW)(" for the step-by-step credentials + webhook walkthrough.",-1))])]),a[9]||(a[9]=(0,s.Fv)('<h2 id="what-it-does" tabindex="-1"><a class="header-anchor" href="#what-it-does"><span>What It Does</span></a></h2><table><thead><tr><th>For</th><th>Means</th></tr></thead><tbody><tr><td><strong>Customer</strong></td><td>Picks &quot;PayPal&quot; as the withdrawal method, enters their PayPal email. Gets paid into PayPal once admin approves</td></tr><tr><td><strong>Admin</strong></td><td>One-click approve → plugin calls PayPal&#39;s Payouts API. No spreadsheet exports, no manual transfers</td></tr></tbody></table><p><img src="/wp-wallet-system/images/admin-paypal-payout.webp" alt="PayPal Automatic Payouts settings — client ID, secret, sandbox toggle, webhook"></p><h2 id="what-you-need" tabindex="-1"><a class="header-anchor" href="#what-you-need"><span>What You Need</span></a></h2><ul><li>A PayPal <strong>Business</strong> account</li><li>API credentials (Client ID + Secret) from your PayPal app</li><li>Webhook URL registered in your PayPal app (for status sync)</li></ul><h2 id="setup" tabindex="-1"><a class="header-anchor" href="#setup"><span>Setup</span></a></h2><h3 id="_1-get-api-credentials" tabindex="-1"><a class="header-anchor" href="#_1-get-api-credentials"><span>1. Get API credentials</span></a></h3><ol><li>Log in to <a href="https://developer.paypal.com" target="_blank" rel="noopener noreferrer">developer.paypal.com</a></li><li><strong>Apps &amp; Credentials</strong></li><li>Create app (sandbox first, then live)</li><li>Copy <strong>Client ID</strong> + <strong>Secret</strong></li></ol><h3 id="_2-plugin-settings" tabindex="-1"><a class="header-anchor" href="#_2-plugin-settings"><span>2. Plugin settings</span></a></h3><p><strong>Wallet → Settings → Payout → PayPal</strong></p><table><thead><tr><th>Field</th><th>Notes</th></tr></thead><tbody><tr><td>Enable</td><td>toggle exposure on the withdrawal method radio</td></tr><tr><td>Mode</td><td><code>sandbox</code> for testing / <code>live</code> for production</td></tr><tr><td>Sandbox Client ID</td><td>from your sandbox app</td></tr><tr><td>Sandbox Secret</td><td>from your sandbox app</td></tr><tr><td>Live Client ID</td><td>from your live app</td></tr><tr><td>Live Secret</td><td>from your live app</td></tr><tr><td>Currency</td><td>base currency for payouts</td></tr><tr><td>Sender batch prefix</td><td>e.g. <code>WK-WDRW-</code> (helps reconcile in PayPal dashboard)</td></tr><tr><td>Webhook URL</td><td>shown read-only — copy into PayPal app webhooks</td></tr></tbody></table><h3 id="_3-register-the-webhook" tabindex="-1"><a class="header-anchor" href="#_3-register-the-webhook"><span>3. Register the webhook</span></a></h3><p>In your PayPal app settings → <strong>Webhooks</strong> → add the URL the plugin shows. Subscribe to:</p><ul><li><code>PAYMENT.PAYOUTS-ITEM.SUCCEEDED</code></li><li><code>PAYMENT.PAYOUTS-ITEM.FAILED</code></li><li><code>PAYMENT.PAYOUTS-ITEM.REFUNDED</code></li><li><code>PAYMENT.PAYOUTS-ITEM.RETURNED</code></li><li><code>PAYMENT.PAYOUTS-ITEM.UNCLAIMED</code></li></ul><p>PayPal will POST to that URL on each event — plugin auto-updates the matching withdrawal status.</p><h2 id="how-approval-works" tabindex="-1"><a class="header-anchor" href="#how-approval-works"><span>How Approval Works</span></a></h2><p>When admin clicks <strong>Approve</strong> on a PayPal-method withdrawal:</p><ol><li>Plugin calls PayPal Payouts with the customer&#39;s amount + email</li><li>PayPal returns batch + item IDs (saved for reconciliation)</li><li>Status flips <code>pending</code> → <code>approved</code></li><li>When PayPal webhook fires <code>PAYMENT.PAYOUTS-ITEM.SUCCEEDED</code> → status flips to <code>paid</code></li><li>On failure → status <code>failed</code>, admin can retry</li></ol><h2 id="sandbox-vs-live" tabindex="-1"><a class="header-anchor" href="#sandbox-vs-live"><span>Sandbox vs Live</span></a></h2><table><thead><tr><th>Mode</th><th>Use for</th><th>Customer email</th></tr></thead><tbody><tr><td><code>sandbox</code></td><td>dev / staging</td><td>sandbox personal accounts (created in developer dashboard)</td></tr><tr><td><code>live</code></td><td>production</td><td>real PayPal email of the customer</td></tr></tbody></table><div class="hint-container warning"><p class="hint-container-title">Mode mismatch</p><p>Sandbox creds with <code>live</code> mode (or vice versa) → &quot;Authentication failed (invalid_client)&quot; error. The plugin guards against the mistake by validating the token endpoint on save.</p></div><h2 id="currency" tabindex="-1"><a class="header-anchor" href="#currency"><span>Currency</span></a></h2><p>PayPal Payouts requires the payout currency to match the receiver&#39;s PayPal account, OR the sender&#39;s account must support cross-currency payouts.</p><p>If a mismatch happens:</p><ul><li>PayPal returns <code>RECEIVER_CURRENCY_MISMATCH</code> or <code>RECEIVER_UNREGISTERED</code></li><li>Plugin marks the row <code>failed</code></li><li>Admin can reject → refund → ask customer to fix</li></ul><h2 id="sender-balance-required" tabindex="-1"><a class="header-anchor" href="#sender-balance-required"><span>Sender Balance Required</span></a></h2><p>PayPal Payouts withdraw from your PayPal Business balance. Top up your PayPal account before approving large withdrawals — failure mode is <code>INSUFFICIENT_FUNDS</code>.</p><h2 id="reconciliation" tabindex="-1"><a class="header-anchor" href="#reconciliation"><span>Reconciliation</span></a></h2><p>The plugin tags every payout with the sender batch ID prefix you set. Easy to find a payout in your PayPal dashboard:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">search PayPal dashboard for: WK-WDRW-</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Or pull from the database:</p><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code><span class="line"><span class="token keyword">SELECT</span> id<span class="token punctuation">,</span> amount<span class="token punctuation">,</span> fee<span class="token punctuation">,</span> JSON_EXTRACT<span class="token punctuation">(</span>error<span class="token punctuation">,</span> <span class="token string">&#39;$.payout_batch_id&#39;</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> paypal_batch</span>\n<span class="line"><span class="token keyword">FROM</span> wp_wkwc_wallet_withdrawal</span>\n<span class="line"><span class="token keyword">WHERE</span> <span class="token keyword">status</span> <span class="token operator">=</span> <span class="token string">&#39;paid&#39;</span> <span class="token operator">AND</span> method <span class="token operator">=</span> <span class="token string">&#39;paypal&#39;</span></span>\n<span class="line">  <span class="token operator">AND</span> paid_at <span class="token operator">&gt;=</span> <span class="token string">&#39;2026-04-01&#39;</span><span class="token punctuation">;</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="when-something-goes-wrong" tabindex="-1"><a class="header-anchor" href="#when-something-goes-wrong"><span>When Something Goes Wrong</span></a></h2><table><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td><code>Authentication failed (invalid_client)</code></td><td>Sandbox creds in live mode, or vice versa. Re-check Mode toggle</td></tr><tr><td><code>RECEIVER_UNREGISTERED</code></td><td>Customer has no PayPal account at that email. Reject + ask customer to update</td></tr><tr><td><code>INSUFFICIENT_FUNDS</code></td><td>Your PayPal Business balance too low. Top up + retry from the row drawer</td></tr><tr><td>Webhook never fires</td><td>URL not registered in PayPal app, OR firewall blocking PayPal&#39;s IPs</td></tr><tr><td>Status stuck on <code>approved</code></td><td>Webhook URL wrong, or events not subscribed. Re-register events</td></tr></tbody></table><details class="hint-container details"><summary>For developers — hooks + reconciliation</summary><h3 id="hooks" tabindex="-1"><a class="header-anchor" href="#hooks"><span>Hooks</span></a></h3><table><thead><tr><th>Hook</th><th>Type</th><th>When</th></tr></thead><tbody><tr><td><code>wkwp_paypal_payout_request_body</code></td><td>filter</td><td>mutate the JSON body before send</td></tr><tr><td><code>wkwp_paypal_payout_response</code></td><td>action</td><td>after PayPal API response</td></tr><tr><td><code>wkwp_paypal_webhook_event</code></td><td>action</td><td>every webhook event received</td></tr></tbody></table><h3 id="api-call-shape" tabindex="-1"><a class="header-anchor" href="#api-call-shape"><span>API call shape</span></a></h3><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">POST /v1/payments/payouts</span>\n<span class="line">{</span>\n<span class="line">  &quot;sender_batch_header&quot;: {</span>\n<span class="line">    &quot;sender_batch_id&quot;: &quot;WK-WDRW-&lt;row_id&gt;&quot;,</span>\n<span class="line">    &quot;email_subject&quot;: &quot;&lt;subject&gt;&quot;</span>\n<span class="line">  },</span>\n<span class="line">  &quot;items&quot;: [{</span>\n<span class="line">    &quot;recipient_type&quot;: &quot;EMAIL&quot;,</span>\n<span class="line">    &quot;amount&quot;: { &quot;value&quot;: &quot;X.XX&quot;, &quot;currency&quot;: &quot;USD&quot; },</span>\n<span class="line">    &quot;receiver&quot;: &quot;customer@paypal.com&quot;,</span>\n<span class="line">    &quot;note&quot;: &quot;Withdrawal #&lt;row_id&gt;&quot;</span>\n<span class="line">  }]</span>\n<span class="line">}</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Response stored on the withdrawal row&#39;s metadata for reconciliation.</p></details><h2 id="related" tabindex="-1"><a class="header-anchor" href="#related"><span>Related</span></a></h2>',36)),(0,s.Lk)("ul",null,[(0,s.Lk)("li",null,[(0,s.bF)(t,{to:"/withdrawal.html"},{default:(0,s.k6)(()=>[...a[4]||(a[4]=[(0,s.eW)("Withdrawal",-1)])]),_:1})]),(0,s.Lk)("li",null,[(0,s.bF)(t,{to:"/stripe-payout.html"},{default:(0,s.k6)(()=>[...a[5]||(a[5]=[(0,s.eW)("Stripe Payout",-1)])]),_:1})]),(0,s.Lk)("li",null,[(0,s.bF)(t,{to:"/admin-settings.html"},{default:(0,s.k6)(()=>[...a[6]||(a[6]=[(0,s.eW)("Admin Settings",-1)])]),_:1})])])])}]]),i=JSON.parse('{"path":"/paypal-payout.html","title":"PayPal Payout","lang":"en-US","frontmatter":{"title":"PayPal Payout","description":"Send wallet withdrawals to a PayPal email address using PayPal\'s Payouts API. Sandbox / Live, webhook status sync, auto-payout on admin approve.","meta":[{"name":"keywords","content":"paypal mass payments, paypal payout woocommerce, paypal withdrawal wallet, paypal sandbox payout"}]},"headers":[{"level":2,"title":"What It Does","slug":"what-it-does","link":"#what-it-does","children":[]},{"level":2,"title":"What You Need","slug":"what-you-need","link":"#what-you-need","children":[]},{"level":2,"title":"Setup","slug":"setup","link":"#setup","children":[{"level":3,"title":"1. Get API credentials","slug":"_1-get-api-credentials","link":"#_1-get-api-credentials","children":[]},{"level":3,"title":"2. Plugin settings","slug":"_2-plugin-settings","link":"#_2-plugin-settings","children":[]},{"level":3,"title":"3. Register the webhook","slug":"_3-register-the-webhook","link":"#_3-register-the-webhook","children":[]}]},{"level":2,"title":"How Approval Works","slug":"how-approval-works","link":"#how-approval-works","children":[]},{"level":2,"title":"Sandbox vs Live","slug":"sandbox-vs-live","link":"#sandbox-vs-live","children":[]},{"level":2,"title":"Currency","slug":"currency","link":"#currency","children":[]},{"level":2,"title":"Sender Balance Required","slug":"sender-balance-required","link":"#sender-balance-required","children":[]},{"level":2,"title":"Reconciliation","slug":"reconciliation","link":"#reconciliation","children":[]},{"level":2,"title":"When Something Goes Wrong","slug":"when-something-goes-wrong","link":"#when-something-goes-wrong","children":[]},{"level":2,"title":"Related","slug":"related","link":"#related","children":[]}],"git":{},"filePathRelative":"paypal-payout.md"}')}}]);